// PPL 2026 — Custom Service Worker
// Pure custom SW — NOT generated by Workbox/VitePWA
// Handles: caching, push notifications, keep-alive ping

const CACHE_VER    = 'ppl2026-v5'
const STATIC_CACHE = `${CACHE_VER}-static`
const IMAGE_CACHE  = `${CACHE_VER}-images`
const API_URL      = 'https://ppl2026-backend.onrender.com'

const PRECACHE = [
  '/manifest.json',
  '/icons/icon-192.png',
  '/icons/icon-512.png',
  '/icons/badge-72.png',
]

// ── Install ─────────────────────────────────────────────────────────
self.addEventListener('install', e => {
  e.waitUntil(
    caches.open(STATIC_CACHE)
      .then(c => c.addAll(PRECACHE).catch(() => {}))
      .then(() => self.skipWaiting())
  )
})

// ── Activate ─────────────────────────────────────────────────────────
self.addEventListener('activate', e => {
  e.waitUntil(
    caches.keys()
      .then(keys => Promise.all(
        keys.filter(k => k !== STATIC_CACHE && k !== IMAGE_CACHE)
            .map(k => caches.delete(k))
      ))
      .then(() => self.clients.claim())
      .then(() => ping())
  )
})

// ── Keep-alive ping every 10 min ─────────────────────────────────────
const ping = () => fetch(`${API_URL}/api/bootstrap`, { cache: 'no-store' }).catch(() => {})
setInterval(ping, 10 * 60 * 1000)

// ── Fetch strategy ────────────────────────────────────────────────────
self.addEventListener('fetch', e => {
  const url = new URL(e.request.url)

  // API — always network, never cache
  if (url.pathname.startsWith('/api/')) {
    e.respondWith(fetch(e.request))
    return
  }

  // External (CDN, fonts) — network first, cache fallback
  if (url.hostname !== self.location.hostname) {
    e.respondWith(fetch(e.request).catch(() => caches.match(e.request)))
    return
  }

  // Images — cache first
  if (e.request.destination === 'image') {
    e.respondWith(
      caches.open(IMAGE_CACHE).then(cache =>
        cache.match(e.request).then(cached => {
          if (cached) return cached
          return fetch(e.request).then(res => {
            if (res.ok) cache.put(e.request, res.clone())
            return res
          })
        })
      )
    )
    return
  }

  // HTML navigation — network first, SPA fallback
  if (e.request.mode === 'navigate') {
    e.respondWith(
      fetch(e.request).catch(() =>
        caches.match('/index.html').then(r => r || fetch('/'))
      )
    )
    return
  }

  // Hashed assets — network first, cache as backup
  if (url.pathname.startsWith('/assets/')) {
    e.respondWith(
      fetch(e.request)
        .then(res => {
          if (res.ok) {
            const clone = res.clone()
            caches.open(STATIC_CACHE).then(c => c.put(e.request, clone))
          }
          return res
        })
        .catch(() => caches.match(e.request))
    )
    return
  }

  // Everything else — network, no cache
  e.respondWith(fetch(e.request).catch(() => caches.match(e.request)))
})

// ── PUSH NOTIFICATIONS ────────────────────────────────────────────────
self.addEventListener('push', e => {
  let payload = {
    title: 'PPL 2026',
    body:  'New update!',
    icon:  '/icons/icon-192.png',
    badge: '/icons/badge-72.png',
    url:   '/',
  }

  try {
    if (e.data) {
      const d = e.data.json()
      payload  = { ...payload, ...d }
    }
  } catch {}

  e.waitUntil(
    self.registration.showNotification(payload.title, {
      body:              payload.body,
      icon:              payload.icon,
      badge:             payload.badge,
      tag:               'ppl2026-notif',
      renotify:          true,
      silent:            false,
      vibrate:           [200, 100, 200, 100, 200],
      requireInteraction: false,
      data:              { url: payload.url || '/' },
    })
  )
})

// ── Notification click ────────────────────────────────────────────────
self.addEventListener('notificationclick', e => {
  e.notification.close()
  const url = e.notification.data?.url || '/'
  e.waitUntil(
    clients.matchAll({ type: 'window', includeUncontrolled: true })
      .then(list => {
        for (const c of list) {
          if (c.url.includes(self.location.origin) && 'focus' in c) {
            c.focus()
            c.navigate(url)
            return
          }
        }
        if (clients.openWindow) return clients.openWindow(url)
      })
  )
})
